import sys
input = sys.stdin.readline
t = int(input())
alpha = 'abcdefghijklmnopqrstuvwxyz'
for _ in range(t):
    n = int(input())
    if n <= 26:
        print(alpha[:n])
    else:
        prefix_len = n - 26
        if prefix_len % 2 == 1:
            print('a' * prefix_len + alpha)
        else:
            print('a' * (prefix_len - 1) + alpha)
